import React from "react";
import {useMediaQuery} from "react-responsive";
import "../App.scss";
import "./main.scss";

import DiscordIcon from "../icon/discord.svg";
import GithubIcon from "../icon/github.svg";
import ProjectsIcon from "../icon/projects.svg";
import DMIcon from "../icon/dm.svg";
import DonateIcon from "../icon/donate.svg";
import HireMeIcon from "../icon/hireme.svg";
import SortIcon from "../icon/sort.svg";
import SearchIcon from "../icon/search.svg";

import {Modals, openModal, copyToClipboard, openImageModal} from "../components/modals";
import Tooltip from "../components/tooltip";
import HeaderItem from "../components/headerItem";
import TabsList from "../components/tabsList";

import RequestFlagIcon from "../icon/flag_request.svg";
import DeprecatedIcon from "../icon/deprecated.svg";
import HeartIcon from "../icon/heart.svg";

const flagIcons =
    {
        Request: RequestFlagIcon,
        Deprecated: DeprecatedIcon,
        Heart: HeartIcon
    };

const SortType =
    {
        Favorites: (x, y) => {
            let xFlag;
            let yFlag;

            const getFlag = f => {
                if (f == "Deprecated")
                    return 2;
                else if (f == "Outdated")
                    return 1;
                return 0;
            };

            if (x.flags && x.flags[0] && x.flags[0].style)
                xFlag = x.flags[0].style;
            if (y.flags && y.flags[0] && y.flags[0].style)
                yFlag = y.flags[0].style;

            if (getFlag(xFlag) < getFlag(yFlag))
                return -1;
            else if (getFlag(xFlag) > getFlag(yFlag))
                return 1;
            return 0;
        },
        Name: ({ name: x }, { name: y }) => {
            if (x.toLowerCase() < y.toLowerCase())
                return -1;
            else if (x.toLowerCase() > y.toLowerCase())
                return 1;
            return 0;
        }
    };

const Header = () => {
    const isMobile = useMediaQuery({ query: "(max-width: 1224px)" });

    const toggleHeader = e => {
        if (isMobile) {
            if (e.target.classList.contains("HeaderItems") || e.target.classList.contains("MainHeader")) {
                const items = document.getElementsByClassName("HeaderItems")[0].classList;

                if (items.contains("Collapsed"))
                    items.remove("Collapsed");
                else
                    items.add("Collapsed");
            }
        }
    };

    return (
        <header className="Header">
            <span className="MainHeader" onClick={toggleHeader}>Tom's Discord Stuff</span>
            <SearchBar/>
            <span className={"HeaderItems" + (isMobile ? " Collapsed" : "")} onClick={toggleHeader}>
				<HeaderItem icon={SortIcon} content="Switch item sorting mode" action={() => switchItemListSort()}
                            scale={0.9}/>
				<HeaderItem icon={HireMeIcon} content="Contact/Hire me!"
                            action={() => window.location.assign("#/contact")}/>
				<HeaderItem icon={DonateIcon} content="Buy me a cheeseburger ♥"
                            action={() => window.open("https://www.paypal.me/israelboone")} scale={0.8}/>
				<HeaderItem icon={ProjectsIcon} content="View my other projects"
                            action={() => window.location.assign("#/projects")} scale={0.7}/>
				<HeaderItem icon={GithubIcon} content="View my GitHub page"
                            action={() => window.open("https://github.com/Metalloriff")}/>
				<HeaderItem icon={DMIcon} content="Copy my Discord tag"
                            action={() => copyToClipboard("Metalloriff 💕🌈#2891")}/>
				<HeaderItem icon={DiscordIcon} content="Join my Discord server"
                            action={() => window.open("https://discord.gg/yNqzuJa")}/>
			</span>
        </header>
    );
};

class Main extends React.Component {
    state = { pluginList: [], botList: [], loaded: false };

    async componentDidMount() {
        this.setState({
            pluginList: await (await fetch("https://dl.dropboxusercontent.com/s/hltcob7d3qvtga6/plugins.json?raw=1", { cache: "no-cache" })).json(),
            botList: await (await fetch("https://dl.dropboxusercontent.com/s/jd38yjtsz2qw5yz/bots.json?raw=1", { cache: "no-cache" })).json(),
            loaded: true
        });
    }

    render() {
        const { pluginList, botList, loaded } = this.state;

        return (
            <div>
                <Header/>

                <div className="Main">
                    <div id="ErrorText" className="ErrorText" style={{
                        lineHeight: window.innerHeight + "px",
                        display: "none"
                    }}>Failed to fetch addon list! Please contact me regarding this issue.
                    </div>

                    <TabsList tabs={["Plugins", "Themes", "CSS", "Bots"]}>
                        <ItemList tab="Plugins" items={pluginList} type="Plugin"/>
                        <ItemList tab="Bots" items={botList} type="Bot"/>
                    </TabsList>

                    <Modals/>
                </div>

                <footer className="Footer">
					<span className="FooterItems">
						<span>Licenses - </span>
						<BasicLink link="https://fontawesome.com/license"/>
						<span> | Copyright © 2020 Israel Boone</span>
					</span>
                </footer>
            </div>
        );
    }
}

class SearchBar extends React.Component {
    constructor(props) {
        super(props);
        this.state = { focused: false };
    }

    updateFocus(f, e) {
        this.setState({ focused: f || e.currentTarget.value.length > 0 });
    }

    render() {
        return (
            <span className={"SearchBar" + (this.state.focused ? " Focused" : "")}>
				<input onFocus={e => this.updateFocus(true, e)} onBlur={e => this.updateFocus(false, e)}
                       onChange={e => filterItemList(e.target.value)}/>
				<img src={SearchIcon}/>
			</span>
        );
    }
}

let switchItemListSort;
let filterItemList;

class ItemList extends React.Component {
    constructor() {
        super();

        this.state =
            {
                sort: SortType.Favorites,
                filter: ""
            };
    }

    componentDidMount() {
        switchItemListSort = () => this.setState({ sort: this.state.sort == SortType.Favorites ? SortType.Name : SortType.Favorites });
        filterItemList = filter => this.setState({ filter });
    }

    render() {
        const items = [...this.props.items]
            .sort(this.state.sort)
            .filter(m => m.name.toLowerCase().includes(this.state.filter));

        return (
            <div className="Items">
                {
                    items != null && items.length > 0
                        ? items.map(item => (<Item key={item.name} {...this.props} {...item}
                                                   displayName={item.name.replace(/[A-Z](?=[a-z])/g, c => " " + c)}/>))
                        : (<div className="NoContentsMessage">Fetching...</div>)
                }
            </div>
        );
    }
}

class Item extends React.Component {
    getSource(src) {
        if (this.props.overrideSources != null && this.props.overrideSources[src] != null)
            return (this.props.overrideSources[src]);

        switch (this.props.type) {
            case "Plugin":
                const url = `https://github.com/Metalloriff/BetterDiscordPlugins/blob/master/${this.props.name}.plugin.js`;
                const raw = `https://raw.githubusercontent.com/Metalloriff/BetterDiscordPlugins/master/${this.props.name}.plugin.js`;

                switch (src) {
                    case "source":
                        return url;
                    case "raw":
                        return raw;
                }
        }
    }

    footer() {
        switch (this.props.type) {
            case "Plugin":
            case "Theme":
                return (
                    <div className="ItemFooter">
                        <div className="ItemButton"
                             onClick={() => openModal((<MoreInfoModal {...this.props} src={this.getSource("raw")}/>))}>
							<span>
								More Info
							</span>
                        </div>
                        <div className="ItemButton" onClick={() => {
                            if (this.props.overrideSources && this.props.overrideSources["download"])
                                return window.open(this.props.overrideSources["download"]);
                            
                            const source = this.getSource("raw");
                            if (!source || !source.length)
                                return;
                            
                            const e = document.createElement("a");
                            e.setAttribute("href", "data:text/plain;charset=utf-8," + encodeURIComponent(source));
                            e.setAttribute("download", source.split("/")[source.split("/").length - 1]);
                            
                            e.style.display = "none";
                            document.body.appendChild(e);
                            
                            e.click();
                            
                            document.body.removeChild(e);
                        }}>
							<span>
								Download
							</span>
                        </div>
                        <div className="ItemButton" onClick={() => window.open(this.getSource("source"))}>
							<span>
								View Source
							</span>
                        </div>
                    </div>);
            case "Bot":
                return (
                    <div className="ItemFooter">
                        <div className="ItemButton" onClick={() => window.open(this.props.invite)}>
							<span>
								Invite To Server
							</span>
                        </div>
                        <Tooltip text="No source available" hidden={this.props.source != null} style={{ top: 65 }}>
                            <div className={"ItemButton" + (this.props.source == null ? " Disabled" : "")}
                                 onClick={this.props.source != null ? () => window.open(this.props.source) : null}>
								<span>
									View Source
								</span>
                            </div>
                        </Tooltip>
                    </div>
                )
            default:
                return null;
        }
    }

    render() {
        return (
            <div className={"Item " + (((this.props.flags || [])[0] || {}).style || this.props.type)}>
                <div className="ItemHeader">
                    <span className="ItemLabel">{this.props.displayName}</span>
                    {
                        this.props.flags == null ? null :
                            <span className="ItemFlags">
							{this.props.flags.map(flag => (<ItemFlag key={this.props.flags.indexOf(flag)} {...flag}/>))}
						</span>
                    }
                </div>
                <div className="ItemDescription">{this.props.description}</div>
                {this.footer()}
            </div>
        );
    }
}

class MoreInfoModal extends React.Component {
    constructor() {
        super();

        this.state = { ready: false, data: null }
    }

    componentDidMount = () =>
        fetch(this.props.src)
            .then(res => res.text())
            .then(data => this.setState({ ready: true, data }))
            .catch(() => this.setState({ ready: true, data: "ERROR" }));

    render() {
        let data;

        if (this.state.ready) {
            data = this.state.data == "404: Not Found" ?
                {
                    version: "NA",
                    sizeLabel: "NA"
                } :
                {
                    version: ((/version: "(.*)"/g).exec(this.state.data) || [, "NA"])[1],
                    size: this.state.data.length,
                    sizeLabel: this.state.data.length > 1024
                        ? (this.state.data.length / 1024).toFixed(2) + "kb"
                        : this.state.data.length + "b"
                };
        }

        return (
            <div className="MoreInfoModal">
                <div className="InfoName">{this.props.displayName}</div>
                <div className="InfoDesc">Description:<br/><span className="Sub">{this.props.description}</span></div>

                {this.props.previews != null && this.props.previews.length > 0 ?
                    (<div className="InfoMedia">
                        <div className="InfoDesc">Images ({this.props.previews.length})</div>
                        {this.props.previews.map(src =>
                            (<span onClick={() => openImageModal(src)} key={this.props.previews.indexOf(src)}
                                   className="InfoPreview" style={{ backgroundImage: `url(${src})` }}/>))}
                    </div>) : null}

                {data != null ?
                    (<div className="InfoFooter">
                        <span className="InfoFooterItem">Version: <span className="Sub">{data.version}</span></span>
                        <span className="InfoFooterItem">Size: <span className="Sub">{data.sizeLabel}</span></span>
                    </div>) : null}
            </div>
        )
    }
}

class ItemFlag extends React.Component {
    render() {
        return (
            <Tooltip text={this.props.tooltip || ""}>
                <img className="ItemFlag" src={flagIcons[this.props.icon]}
                     style={{ cursor: this.props.link == null ? "normal" : "pointer" }}
                     onClick={this.props.link == null ? null : () => window.open(this.props.link)}/>
            </Tooltip>
        );
    }
}

class BasicLink extends React.Component {
    render() {
        return (
            <a className={this.props.className} href={this.props.link}>{this.props.text || this.props.link}</a>
        )
    }
}

export default Main;